var medianSlidingWindow = function(nums, k) {
    const lower = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < x) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    const window = nums.slice(0, k).sort((a, b) => a - b);
    const res = [];
    for (let i = k; i <= nums.length; i++) {
        if (k % 2) {
            res.push(window[(k - 1) >> 1]);
        } else {
            res.push((window[k / 2 - 1] + window[k / 2]) / 2);
        }
        if (i === nums.length) break;
        const out = nums[i - k];
        window.splice(lower(window, out), 1);
        const ins = nums[i];
        window.splice(lower(window, ins), 0, ins);
    }
    return res;
};
